const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  amulet: 60,
  rune: 25,
};
const BLOCK_OF_THREE_PREMIUM = 60;
const BLOCK_SIZE = 3;

const basePremiumForItem = (item: QuoteItem): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;

const countItemsOfType = (items: QuoteItem[], type: string): number =>
  items.filter((item) => item.type === type).length;

const blockPremiumForType = (items: QuoteItem[], type: string): number | null =>
  countItemsOfType(items, type) === BLOCK_SIZE ? BLOCK_OF_THREE_PREMIUM : null;

const sumBasePremiums = (items: QuoteItem[]): number => {
  const runeBlock = blockPremiumForType(items, "rune");
  if (runeBlock !== null) return runeBlock;
  return items.reduce((total, item) => total + basePremiumForItem(item), 0);
};
